public static boolean checkExist(tableId _refTableid, recId _refRecid )
{
    boolean ret = true;

    if (!ETGLedgerJournalTransAccrualTrans::exist(_refTableid, _refRecid))
    {
        ret = checkFailed(strfmt(ETGLedgerJournalTransAccrualTrans::txtNotExist(), _refTableid, _refRecid));
    }

    return ret;
}

/// <summary>
/// Delete all records from the table related to reference tableid and recid.
/// </summary>
/// <param name = "_refTableid">Reference table id</param>
/// <param name = "_refRecid">Reference record id</param>
public static void deleteById(tableId _refTableid, recId _refRecid)
{
    ETGLedgerJournalTransAccrualTrans accrualTrans;
    LedgerAccrualTable ledgerAccrualTable = LedgerAccrualTable::find(ETGLedgerJournalTransAccrual::find(_refTableid, _refRecid).AccrualId);
    RefRecId numberSequenceRefRecId = ledgerAccrualTable.NumberSequenceTable;

    ttsbegin;

    if (ETGLedgerJournalTransAccrualTrans::shouldReleaseVouchers())
    {
        ETGLedgerJournalTransAccrualTrans::releaseVouchers(numberSequenceRefRecId, _refTableid, _refRecid);
    }

    delete_from accrualTrans
        where accrualTrans.RefTableid == _refTableid
            && accrualTrans.RefRecid == _refRecid;

    ttscommit;
}

/// <summary>
/// Releases the vouchers based on number sequence record of accrual record and voucher.
/// </summary>
/// <param name="_numberSequenceRefRecId">The number sequence reference record ID.</param>
/// <param name="_refTableid">Table ID of referenced table.</param>
/// <param name="_refRecid">The record ID of referenced table.</param>
protected static void releaseVouchers(RefRecId _numberSequenceRefRecId, TableId _refTableid, RecId _refRecid)
{
    ETGLedgerJournalTransAccrualTrans accrualTrans;

    if (_numberSequenceRefRecId)
    {
        while select Voucher from accrualTrans
            order by Voucher
            group by Voucher
            where accrualTrans.RefTableid == _refTableid
                && accrualTrans.RefRecid == _refRecid
        {
            NumberSeq::releaseNumber(_numberSequenceRefRecId, accrualTrans.Voucher);
        }
    }
}

/// <summary>
/// Determines whether the vouchers should be released or not.
/// </summary>
/// <returns>
/// true if the voucher is released; otherwise, false.
/// </returns>
protected static boolean shouldReleaseVouchers()
{
    return true;
}

/// <summary>
/// CHeck if record exist on given paramaters.
/// </summary>
/// <param name = "_refTableid">Reference table id</param>
/// <param name = "_refRecid">Reference rec id</param>
/// <returns>Return true if record exists</returns>
public static boolean exist(tableId _refTableid, recId _refRecid )
{
    boolean found;

    found = (select firstonly
                 RecId
            from
                 etgLedgerJournalTransAccrualTrans
             where
                 etgLedgerJournalTransAccrualTrans.RefTableid == _refTableid &&
                etgLedgerJournalTransAccrualTrans.RefRecid == _refRecid).RecId != 0;

    return found;
}

/// <summary>
/// Find record for given parameteters.
/// </summary>
/// <param name = "_refTableid">Reference table id</param>
/// <param name = "_refRecid">Reference recid</param>
/// <param name = "_forupdate">true or false</param>
/// <param name = "_concurrencyModel">default value</param>
/// <returns>Returns the table intance found</returns>
public static ETGLedgerJournalTransAccrualTrans find(
    tableId _refTableid,
    recId _refRecid ,
    boolean                 _forupdate = false,
    ConcurrencyModel        _concurrencyModel = ConcurrencyModel::Auto)
{
    ETGLedgerJournalTransAccrualTrans ledgerJournalTransAccrualTrans;

    ledgerJournalTransAccrualTrans.selectForUpdate(_forupdate);

    if (_forupdate  && _concurrencyModel != ConcurrencyModel::Auto)
    {
        ledgerJournalTransAccrualTrans.concurrencyModel(_concurrencyModel);
    }

    select firstonly ledgerJournalTransAccrualTrans
        where ledgerJournalTransAccrualTrans.RefTableid == _refTableid &&
            ledgerJournalTransAccrualTrans.RefRecid == _refRecid;

    return ledgerJournalTransAccrualTrans;
}

/// <summary>
/// Sync the voucher created.
/// </summary>
/// <param name = "_newVoucher">new voucher number</param>
/// <param name = "_refTableID">reference table id</param>
/// <param name = "_refRecID">reference rec id</param>
public static void synchronizeVoucher(
    Voucher _newVoucher,
    tableId _refTableID,
    recId   _refRecID)
{
    ETGLedgerJournalTransAccrualTrans ledgerJournalTransAccrualTrans;

    select firstonly ledgerJournalTransAccrualTrans
        where ledgerJournalTransAccrualTrans.RefTableid == _refTableID  &&
              ledgerJournalTransAccrualTrans.RefRecid   == _refRecID    &&
              ledgerJournalTransAccrualTrans.Voucher    != _newVoucher;

    if (ledgerJournalTransAccrualTrans)
    {
        update_recordset ledgerJournalTransAccrualTrans setting Voucher = _newVoucher
            where ledgerJournalTransAccrualTrans.RefTableid == _refTableID  &&
                  ledgerJournalTransAccrualTrans.RefRecid   == _refRecID    &&
                  ledgerJournalTransAccrualTrans.Voucher    != _newVoucher;
    }
}

/// <summary>
/// Update if voucher is changed
/// </summary>
/// <param name = "_journalNum">Ledger journal number</param>
/// <param name = "_baseVoucher">Base voucher</param>
/// <param name = "_baseTransdate">base transaction date</param>
/// <param name = "_refTableid">reference table id</param>
/// <param name = "_refRecid">reference record id</param>
public static void updateLedgerJournalVoucherChanged(
    LedgerJournalId    _journalNum,
    Voucher            _baseVoucher,
    TransDate          _baseTransdate,
    tableId            _refTableid,
    recId              _refRecid)
{
    LedgerJournalVoucherChanged     ledgerJournalVoucherChanged;
    LedgerJournalVoucherChanged     ledgerJournalVoucherChangedForConflict;
    ETGLedgerJournalTransAccrualTrans  ledgerJournalTransAccrualTrans;

    ledgerJournalVoucherChanged.JournalNum = _journalNum;
    ledgerJournalVoucherChanged.FromDate = _baseTransdate;
    ledgerJournalVoucherChanged.FromVoucher = _baseVoucher;
    while   select  ledgerJournalTransAccrualTrans
            group by Voucher, TransDate
            where   ledgerJournalTransAccrualTrans.RefTableid == _refTableid
            &&      ledgerJournalTransAccrualTrans.RefRecid   == _refRecid
            &&     (ledgerJournalTransAccrualTrans.Voucher    != _baseVoucher
            ||      ledgerJournalTransAccrualTrans.TransDate  != _baseTransdate)
            notexists join ledgerJournalVoucherChangedForConflict
            where ledgerJournalVoucherChangedForConflict.ToDate      == ledgerJournalTransAccrualTrans.TransDate
               && ledgerJournalVoucherChangedForConflict.ToVoucher   == ledgerJournalTransAccrualTrans.Voucher
               && ledgerJournalVoucherChangedForConflict.JournalNum  == _journalNum
               && ledgerJournalVoucherChangedForConflict.FromDate    == _baseTransdate
               && ledgerJournalVoucherChangedForConflict.FromVoucher == _baseVoucher
    {
        ledgerJournalVoucherChanged.ToDate = ledgerJournalTransAccrualTrans.TransDate;
        ledgerJournalVoucherChanged.ToVoucher = ledgerJournalTransAccrualTrans.Voucher;
        ledgerJournalVoucherChanged.insert();
    }
}

/// <summary>
///
/// </summary>
public static void updateTempVoucherNum(LedgerJournalId journalId)
{
    ETGLedgerJournalTransAccrualTrans ledgerJournalTransAccrualTrans, ledgerJournalTransAccrualTransCheck;
    LedgerJournalTrans ledgerJournalTrans;
    GeneralJournalAccountEntry generalJournalAccountEntry,generalJournalAccountEntryloc;
    GeneralJournalEntry generalJournalEntry,generalJournalEntryloc;
    select firstonly ledgerJournalTrans
        where ledgerJournalTrans.JournalNum == journalId;

    update_recordset ledgerJournalTransAccrualTrans
        setting OriginalVoucher = ledgerJournalTrans.Voucher
        where ledgerJournalTransAccrualTrans.RefRecid == ledgerJournalTrans.RecId
            && ledgerJournalTransAccrualTrans.RefTableid == tablenum(LedgerJournalTrans)
            && ledgerJournalTransAccrualTrans.JournalNumSource == journalId;

    select firstonly RecId, Voucher, AccrualId, OriginalVoucher from ledgerJournalTransAccrualTransCheck
         where ledgerJournalTransAccrualTransCheck.RefRecid == ledgerJournalTrans.RecId
            && ledgerJournalTransAccrualTransCheck.RefTableid == tablenum(LedgerJournalTrans)
            && ledgerJournalTransAccrualTransCheck.JournalNumSource == journalId;



    if(ledgerJournalTransAccrualTransCheck.RecId)
    {
        select firstonly RecId from generalJournalEntry
            where generalJournalEntry.SubledgerVoucher == ledgerJournalTransAccrualTransCheck.OriginalVoucher;

        if(generalJournalEntry.RecId)
        {
            while select forupdate generalJournalAccountEntry
                where generalJournalAccountEntry.GeneralJournalEntry == generalJournalEntry.RecId
                    && generalJournalAccountEntry.TransactionCurrencyAmount > 0
            {
                String30 mainAcc = MainAccount::find(generalJournalAccountEntry.MainAccount).MainAccountId;
                RecId dimDefault          = LedgerDimensionFacade::getDefaultDimensionFromLedgerDimension(generalJournalAccountEntry.LedgerDimension);
                RecId debitMainAccount    = LedgerAccrualTable::find(ledgerJournalTransAccrualTransCheck.AccrualId).DebitLedgerDimension;
                RecId ledgerDimETG = CostLedgerDimensionDerivationRule::createLedgerDimension(debitMainAccount, dimDefault);
                if(ledgerDimETG)
                {
                    String30 debitAccrualAcc                   = LedgerDimensionFacade::getMainAccountIdFromLedgerDimension(ledgerDimETG);
                    generalJournalAccountEntry.LedgerAccount   = strReplace(generalJournalAccountEntry.LedgerAccount, mainAcc, debitAccrualAcc);
                    generalJournalAccountEntry.LedgerDimension = ledgerDimETG;
                    generalJournalAccountEntry.MainAccount     = debitMainAccount;
                    generalJournalAccountEntry.doUpdate();
                    ledgerJournalTransAccrualTrans.ledgeraccount(debitAccrualAcc,generalJournalAccountEntry,ledgerJournalTrans);
                  //  this.ledgeraccount(mainAcc,generalJournalAccountEntryloc,ledgerJournalTrans);
                }
            }

            while select forupdate generalJournalAccountEntryloc
               where generalJournalAccountEntryloc.GeneralJournalEntry == generalJournalEntry.RecId
                 &&  generalJournalAccountEntryloc.TransactionCurrencyAmount < 0
            {

                String30 mainAcclock = MainAccount::find(generalJournalAccountEntryloc.MainAccount).MainAccountId;
                if(mainAcclock)
                {
                    ledgerJournalTransAccrualTrans.ledgeraccount(mainAcclock,generalJournalAccountEntryloc,ledgerJournalTrans);
                }

            }

        }
    }

}

public void ledgeraccount(String30 _mainAcc,GeneralJournalAccountEntry _generalJournalAccountEntryloc,LedgerJournalTrans _ledgerJournalTrans)
{
    DimensionAttributeValueCombination    dimensionAttributeValueCombination,dimensionAttributeValueCombinationloc;
    ETGCostDistributionsLines             eTGCostDistributionsLines;
    ETGCostDistributionsHeader            etgcostDisttributionheader;
    str                                   mainaccountloc;
    DimensionFinancialTag                 dimensionfinancialtag;
    int                                   i = 1;
    ETGLedgerJournalTransAccrual          etgledgerJournalTransAccrual;

    select firstonly etgledgerJournalTransAccrual where etgledgerJournalTransAccrual.RefRecid == _ledgerJournalTrans.RecId;
    select * from dimensionAttributeValueCombination where DimensionAttributeValueCombination.RecId == _ledgerJournalTrans.LedgerDimension;

    container    mainaccount                    = str2con(dimensionAttributeValueCombination.DisplayValue, '|');
    mainaccountloc                              = conPeek(mainaccount,1);
    AmountCur transorgcurrencyamount             =  _generalJournalAccountEntryloc.TransactionCurrencyAmount;
    AmountCur accountingCurrencyAmountorig       = _generalJournalAccountEntryloc.AccountingCurrencyAmount;
    AmountCur ReportingCurrencyAmountorig        = _generalJournalAccountEntryloc.ReportingCurrencyAmount;


    select firstonly etgcostDisttributionheader where etgcostDisttributionheader.ETGCostAllocationRuleId == etgledgerJournalTransAccrual.CostAllocationRuleId;

    if(!etgcostDisttributionheader)
            throw error('Rule Id not exists in Cost distribution');        

    while  select eTGCostDistributionsLines
            where eTGCostDistributionsLines.ETGMainAccount == mainaccountloc
            && eTGCostDistributionsLines.ETGRefRecId == etgcostDisttributionheader.RecId
    {

        DimensionDefault                    defaultDimension, defaultDimensionOffSet;
        DimensionAttributeValueSetStorage   dimStorage = new DimensionAttributeValueSetStorage();
        DimensionAttributeValueSetStorage   dimStorageOffset = new DimensionAttributeValueSetStorage();
        DimensionAttribute                  dimAttribute1, dimAttribute2, dimAttribute1Offset,dimAttribute2Offset;
        DimensionAttributeValue             dimAttributeValue1, dimAttributeValue2, dimAttributeValue1Offset,dimAttributeValue2Offset;
        LedgerParameters                    LedgerParameters;            

        select firstonly LedgerParameters
                   where LedgerParameters.DataAreaId == curExt();

        dimensionAttributeValueCombinationloc          = DimensionAttributeValueCombination::find(_generalJournalAccountEntryloc.LedgerDimension);

        defaultDimension          = LedgerDimensionFacade::getDefaultDimensionFromLedgerDimension(dimensionAttributeValueCombinationloc.RecId);
        dimStorage                = DimensionAttributeValueSetStorage::find(defaultDimension);

        if(eTGCostDistributionsLines.ETGFDVertical)
        {
            dimAttribute1        = DimensionAttribute::findByName(LedgerParameters.ETGCostDistributionVerticalDimension);
            dimAttributeValue1   = DimensionAttributeValue::findByDimensionAttributeAndValue(dimAttribute1,eTGCostDistributionsLines.ETGFDVertical, true, true);
            dimStorage.addItem(dimAttributeValue1);
        }

        if(eTGCostDistributionsLines.ETGFDSubVertical)
        {
            dimAttribute2        = DimensionAttribute::findByName(LedgerParameters.ETGCostDistributionSubVerticalDimension);
            dimAttributeValue2   = DimensionAttributeValue::findByDimensionAttributeAndValue(dimAttribute2,eTGCostDistributionsLines.ETGFDSubVertical, true, true);
            dimStorage.addItem(dimAttributeValue2);
        }

        defaultDimension = dimStorage.save();
        _generalJournalAccountEntryloc.LedgerDimension = LedgerDimensionFacade::serviceCreateLedgerDimension(LedgerDefaultAccountHelper::getDefaultAccountFromMainAccountRecId(
                                MainAccount::findByMainAccountId(_mainAcc).RecId), defaultDimension);

        ttsbegin;


        if(i==1)
        {
            _generalJournalAccountEntryloc.LedgerAccount = DimensionAttributeValueCombination::find(_generalJournalAccountEntryloc.LedgerDimension).DisplayValue;
            _generalJournalAccountEntryloc.TransactionCurrencyAmount = transorgcurrencyamount * eTGCostDistributionsLines.ETGLinePercentage/100;
            _generalJournalAccountEntryloc.AccountingCurrencyAmount = accountingCurrencyAmountorig * eTGCostDistributionsLines.ETGLinePercentage/100;
            _generalJournalAccountEntryloc.ReportingCurrencyAmount = ReportingCurrencyAmountorig  * eTGCostDistributionsLines.ETGLinePercentage/100;
            _generalJournalAccountEntryloc.update();
            i++;
        }
        else
        {
            _generalJournalAccountEntryloc.LedgerAccount = DimensionAttributeValueCombination::find(_generalJournalAccountEntryloc.LedgerDimension).DisplayValue;
            _generalJournalAccountEntryloc.TransactionCurrencyAmount = transorgcurrencyamount * eTGCostDistributionsLines.ETGLinePercentage/100;
            _generalJournalAccountEntryloc.AccountingCurrencyAmount = accountingCurrencyAmountorig * eTGCostDistributionsLines.ETGLinePercentage/100;
            _generalJournalAccountEntryloc.ReportingCurrencyAmount = ReportingCurrencyAmountorig  * eTGCostDistributionsLines.ETGLinePercentage/100;
            _generalJournalAccountEntryloc.insert();
        }
        ttscommit;

    }

}
